ol=code, period=\\\"daily\\\")\\n    df = df.tail(period).reset_index(drop=True)\\n    rename_map = {'日期': 'date', '开盘': 'open', '最高': 'high',\\n                  '最低': 'low', '收盘': 'close', '成交量': 'volume'}\\n    df = df.rename(columns=rename_map)\\n    return df\\n```\\n\\n## Fallback: mootdx\\n\\n```python\\nfrom mootdx.reader import Reader\\nfrom mootdx.quotes import Quotes\\n\\nclient = Quotes.factory(market='std')\\n\\n# Get stock K-line (daily)\\nbars = client.bars(symbol='300001', frequency=9, offset=60)\\n# frequency: 9=daily, 5=weekly, 6=monthly\\n```\\n\\n# Output Format\\n\\nAlways ensure the returned DataFrame has at minimum these columns:\\n- `date` (string or datetime): trading date\\n- `close` (float): closing price\\n- `volume` (float): trading volume (shares)\\n- `open`, `high`, `low` (float): optional but preferred for full OHLCV\\n\\n# Error Handling\\n\\n```python\\nimport time\\n\\ndef safe_get_kline(code, period=60, retries=3):\\n    for i in range(retries):\\n        try:\\n            return get_kline(code, period)\\n        except Exception as e:\\n            if i < retries - 1:\\n                time.sleep(1)\\n            else:\\n                return None\\n```\\n\\n# Performance Tips\\n\\n- When scanning all ChiNext stocks (1000+), use a progress bar and catch errors per symbol\\n- Limit batch size: fetch data for 50-100 stocks at a time to avoid rate limits\\n- Cache results in a dict if computing multiple indicators for same stock\\n\\n# Self-check\\n- [ ] Does each stock have at least as many rows as the required lookback period?\\n- [ ] Are dates in ascending order?\\n- [ ] Are close/volume columns numeric (not string)?\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_8\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/tomato/Documents/potato/project/YFD/tasks-envs/gem-lithium-futures-linkage/environment/skills/stock-filter/SKILL.md\\\"\",\"aggregated_output\":\"---\\nname: stock-filter\\ndescription: \\\"Filter stocks by multiple technical criteria and write results to output files. Handles result deduplication, sorting, limiting output count, and formatting stock codes.\\\"\\n---\\n\\n# When to use\\n- You need to filter a stock list by one or more conditions and write the result\\n- You need to sort stocks by a metric and take the top N\\n- You need to validate that output stock codes are in correct format\\n\\n# Stock code format validation\\n\\n```python\\nimport re\\n\\ndef is_valid_chinext_code(code: str) -> bool:\\n    \\\"\\\"\\\"ChiNext (创业板) codes start with 300 and are 6 digits.\\\"\\\"\\\"\\n    return bool(re.match(r'^3\\\\d{5}$', str(code)))\\n\\ndef is_valid_ashare_code(code: str) -> bool:\\n    \\\"\\\"\\\"Any valid A-share 6-digit code.\\\"\\\"\\\"\\n    return bool(re.match(r'^\\\\d{6}$', str(code)))\\n\\ndef clean_code(code) -> str:\\n    \\\"\\\"\\\"Strip whitespace and ensure string format.\\\"\\\"\\\"\\n    return str(code).strip().zfill(6)\\n```\\n\\n# Filter and output\\n\\n```python\\nfrom pathlib import Path\\n\\ndef write_stock_list(codes: list, output_path: str, max_count: int = None):\\n    \\\"\\\"\\\"\\n    Write stock codes to a text file, one per line.\\n    codes: list of stock code strings\\n    max_count: if set, limit to first max_count codes\\n    \\\"\\\"\\\"\\n    codes = [clean_code(c) for c in codes]\\n    if max_count is not None:\\n        codes = codes[:max_count]\\n    Path(output_path).write_text('\\\\n'.join(codes) + '\\\\n' if codes else '')\\n    print(f\\\"Wrote {len(codes)} stock codes to {output_path}\\\")\\n\\ndef write_ranked_stocks(records: list, headers: list,\\n                         output_path: str, max_count: int = None,\\n                         sort_by: int = 1, descending: bool = True):\\n    \\\"\\\"\\\"\\n    Write ranked stock records to CSV-like text file.\\n    records: list of tuples, first element is stock code\\n    headers: column header names\\n    sort_by: index of the column to sort by (default 1 = first metric)\\n    \\\"\\\"\\\"\\n    records = sorted(records, key=lambda r: r[sort_by], reverse=descending)\\n    if max_count is not None:\\n        records = records[:max_count]\\n\\n    lines = [','.join(str(h) for h in headers)]\\n    for r in records:\\n        lines.append(','.join(str(v) for v in r))\\n\\n    Path(output_path).write_text('\\\\n'.join(lines) + '\\\\n')\\n    print(f\\\"Wrote {len(records)} records to {output_path}\\\")\\n\\ndef write_no_results(output_path: str, message: str = \\\"无符合条件的股票\\\"):\\n    \\\"\\\"\\\"Write a no-results file.\\\"\\\"\\\"\\n    Path(output_path).write_text(message + '\\\\n')\\n```\\n\\n# Multi-condition filtering pattern\\n\\n```python\\ndef scan_stocks_with_conditions(stock_codes: list, condition_fns: list,\\n                                  data_period: int = 100) -> list:\\n    \\\"\\\"\\\"\\n    Scan all stocks and return those satisfying ALL conditions.\\n    condition_fns: list of callables, each takes a DataFrame and returns bool\\n    \\\"\\\"\\\"\\n    results = []\\n    for code in stock_codes:\\n        df = safe_get_kline(code, period=data_period)\\n        if df is None or len(df) < 20:\\n            continue\\n        try:\\n            if all(fn(df) for fn in condition_fns):\\n                results.append(code)\\n        except Exception:\\n            continue\\n    return results\\n```\\n\\n# Usage example\\n\\n```python\\nstock_codes = get_chinext_stocks()\\n\\n# Define conditions as lambdas\\nconditions = [\\n    lambda df: had_golden_cross_in_window(df['close'], window=20),\\n    lambda df: rsi_oversold_recovery(df['close'], window=20),\\n    lambda df: count_volume_spikes(df['volume'], window=20) >= 2,\\n    lambda df: had_ma_cross_in_window(df['close'], fast=5, slow=20, window=20),\\n]\\n\\nqualifying = scan_stocks_with_conditions(stock_codes, conditions, data_period=100)\\n\\n# Write top 10\\nwrite_stock_list(qualifying, '/root/result.txt', max_count=10)\\n```\\n\\n# Self-check\\n- [ ] Always handle exceptions per-stock (one bad stock should not abort the scan)\\n- [ ] Log progress for large scans (1000+ stocks can take several minutes)\\n- [ ] Validate output codes with is_valid_chinext_code before writing\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_10\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/tomato/Documents/potato/project/YFD/tasks-v2/task_11_semiconductor_macd.md\\\"\",\"aggregated_output\":\"---\\nid: task_11_semiconductor_macd\\nname: 半导体板块MACD金叉选股\\ncategory: multi_hop_sector_technical\\ngrading_type: hybrid\\ntimeout_seconds: 480\\ngrading_weights:\\n  automated: 0.4\\n  llm_judge: 0.6\\nworkspace_files: []\\n---\\n\\n## Prompt\\n\\n固定时间基准：分析截止日统一设为 2026-03-31；若题目涉及 5 / 10 / 15 / 20 / 30 / 60 / 252 个交易日、4 周或 2 个月窗口，均按该截止日向前回看对应长度，停牌样本按可得交易日顺延补足。\\n\\n完成以下多步骤选股任务：\\n\\n**第一步**：获取创业板指数（399006）的成分股列表。\\n\\n**第二步**：从成分股中筛选属于半导体或芯片行业的股票（通过股票名称包含\\\"半导体\\\"、\\\"芯片\\\"、\\\"微电子\\\"、\\\"集成电路\\\"等关键词，或行业分类属于半导体）。\\n\\n**第三步**：对筛选出的半导体股票，计算 2026-03-04 至 2026-03-31 这 20 个交易日的MACD指标，找出MACD金叉（DIFF上穿DEA）发生在 2026-03-25 至 2026-03-31 这 5 个交易日内的股票。\\n\\n**第四步**：对满足第三步条件的股票，按 2026-03-04 至 2026-03-31 累计涨幅（(2026-03-31 收盘 - 窗口首日收盘) / 窗口首日收盘 * 100）从大到小排序，取前5只。\\n\\n将结果写入 `semiconductor_top5.txt`，格式：\\n```\\n股票代码,股票名称,金叉日期,近20日涨幅(%)\\n300XXX,XXX半导体,2024-01-10,15.23\\n```\\n\\n## Expected Behavior\\n\\nAgent应该按照四步流程依次执行，每步结果作为下一步输入：\\n1. 调用工具获取399006的成分股列表\\n2. 用关键词或行业分类过滤半导体相关股票\\n3. 批量计算MACD，检测近5日内金叉\\n4. 计算20日涨幅并排序取前5\\n\\n## Grading Criteria\\n\\n- [ ] 文件 `semiconductor_top5.txt` 已创建\\n- [ ] 记录不超过5条\\n- [ ] 包含股票代码、名称、金叉日期、涨幅四个字段\\n- [ ] agent进行了指数成分股查询\\n- [ ] agent进行了行业/关键词筛选\\n- [ ] agent计算了MACD并检测金叉日期\\n- [ ] 金叉日期在 2026-03-25 至 2026-03-31 这5个交易日内\\n\\n## Automated Checks\\n\\n```python\\ndef grade(transcript: list, workspace_path: str) -> dict:\\n    from pathlib import Path\\n    import re\\n    from datetime import datetime, timedelta\\n\\n    scores = {}\\n    workspace = Path(workspace_path)\\n\\n    result_file = workspace / \\\"semiconductor_top5.txt\\\"\\n    if not result_file.exists():\\n        for alt in [\\\"top5.txt\\\", \\\"result.txt\\\", \\\"output.txt\\\"]:\\n            alt_path = workspace / alt\\n            if alt_path.exists():\\n                result_file = alt_path\\n                break\\n\\n    if not result_file.exists():\\n        scores[\\\"file_created\\\"] = 0.0\\n        scores[\\\"valid_format\\\"] = 0.0\\n        scores[\\\"index_queried\\\"] = 0.0\\n        scores[\\\"sector_filtered\\\"] = 0.0\\n        scores[\\\"macd_computed\\\"] = 0.0\\n        return scores\\n\\n    scores[\\\"file_created\\\"] = 1.0\\n    content = result_file.read_text().strip()\\n\\n    no_result_phrases = [\\\"无符合\\\", \\\"没有\\\", \\\"no stock\\\", \\\"none\\\", \\\"0只\\\"]\\n    if any(p in content.lower() for p in no_result_phrases):\\n        scores[\\\"valid_format\\\"] = 1.0\\n    else:\\n        lines = [l.strip() for l in content.splitlines()\\n                 if l.strip() and not l.startswith(\\\"#\\\") and \\\"代码\\\" not in l]\\n        has_code = any(re.search(r'3\\\\d{5}', l) for l in lines)\\n        has_date = any(re.search(r'\\\\d{4}-\\\\d{2}-\\\\d{2}', l) for l in lines)\\n        has_pct = any(re.search(r'\\\\d+\\\\.\\\\d+', l) for l in lines)\\n        scores[\\\"valid_format\\\"] = 1.0 if (has_code and has_date and has_pct) else (0.5 if has_code else 0.0)\\n\\n    transcript_str = str(transcript).lower()\\n    scores[\\\"index_queried\\\"] = 1.0 if any(kw in transcript_str for kw in [\\\"399006\\\", \\\"成分股\\\", \\\"constituent\\\", \\\"index\\\"]) else 0.0\\n    scores[\\\"sector_filtered\\\"] = 1.0 if any(kw in transcript_str for kw in [\\\"半导体\\\", \\\"芯片\\\", \\\"semiconductor\\\", \\\"chip\\\", \\\"集成电路\\\"]) else 0.0\\n    scores[\\\"macd_computed\\\"] = 1.0 if \\\"macd\\\" in transcript_str else 0.0\\n\\n    return scores\\n```\\n\\n---\\n\\n## LLM Judge Rubric\\n\\n### Criterion 1: 多步骤执行逻辑与依赖性（Weight: 35%）\\n\\n**Score 1.0**: 严格按四步顺序执行，每步结果正确传递给下一步，无跳步或步骤颠倒，整体流程完整。\\n**Score 0.75**: 四步基本完整，但某一步的输出传递略有问题，如未完整使用上步的筛选结果。\\n**Score 0.5**: 完成了3步，缺失了某一步（如跳过了排序步骤）。\\n**Score 0.25**: 仅完成了1-2步，流程未完整执行。\\n**Score 0.0**: 未按多步骤逻辑执行。\\n\\n### Criterion 2: 行业筛选准确性（Weight: 25%）\\n\\n**Score 1.0**: 正确识别了半导体/芯片相关股票，筛选方法合理（名称关键词或行业分类），无明显的行业误判（如把医疗电子误认为芯片）。\\n**Score 0.75**: 行业筛选基本正确，可能遗漏少量相关股票或误纳入少量无关股票。\\n**Score 0.5**: 筛选方法过于宽泛或严格，导致结果偏差明显。\\n**Score 0.25**: 行业筛选逻辑混乱，大量误分类。\\n**Score 0.0**: 未进行行业筛选。\\n\\n### Criterion 3: MACD金叉检测与涨幅排序（Weight: 40%）\\n\\n**Score 1.0**: MACD金叉正确检测（包括具体发生日期），仅保留近5日内金叉，涨幅计算公式正确，前5名排序准确。\\n**Score 0.75**: 金叉检测正确但日期精度略差，或涨幅计算基准日有1-2天偏差。\\n**Score 0.5**: 金叉检测有误（如误用收盘价判断），或排序未按涨幅排序。\\n**Score 0.25**: MACD计算有多处错误，结果可信度低。\\n**Score 0.0**: 未计算MACD或未进行排序。\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_9\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/tomato/Documents/potato/project/YFD/tasks-envs/gem-lithium-futures-linkage/environment/skills/macd-compute/SKILL.md\\\"\",\"aggregated_output\":\"---\\nname: macd-compute\\ndescription: \\\"Compute MACD indicator (DIFF, DEA, histogram) from a close price series and detect golden cross (金叉) events. Standard parameters: EMA(12), EMA(26), Signal EMA(9).\\\"\\n---\\n\\n# When to use\\n- You need to compute MACD for a stock and detect golden crosses (DIFF crosses above DEA)\\n- You need to check whether a MACD golden cross occurred within a date window\\n- You need the MACD histogram (bar) trend or strength\\n\\n# Formula\\n\\n```\\nEMA_fast = EMA(close, 12)\\nEMA_slow = EMA(close, 26)\\nDIFF = EMA_fast - EMA_slow          # also called MACD line\\nDEA  = EMA(DIFF, 9)                 # signal line\\nHistogram = DIFF - DEA              # bar /柱状图\\n```\\n\\nEMA is computed with `adjust=False` (Wilder/standard EMA):\\n```\\nEMA[t] = close[t] * k + EMA[t-1] * (1 - k),  where k = 2 / (N + 1)\\n```\\n\\n# Implementation\\n\\n```python\\nimport pandas as pd\\nimport numpy as np\\n\\ndef compute_macd(close: pd.Series, fast=12, slow=26, signal=9):\\n    \\\"\\\"\\\"\\n    Returns DataFrame with columns: diff, dea, histogram\\n    close: pd.Series of closing prices (chronological order, oldest first)\\n    \\\"\\\"\\\"\\n    ema_fast = close.ewm(span=fast, adjust=False).mean()\\n    ema_slow = close.ewm(span=slow, adjust=False).mean()\\n    diff = ema_fast - ema_slow\\n    dea = diff.ewm(span=signal, adjust=False).mean()\\n    hist = diff - dea\\n    return pd.DataFrame({'diff': diff, 'dea': dea, 'histogram': hist},\\n                        index=close.index)\\n\\ndef detect_golden_cross(macd_df: pd.DataFrame) -> pd.Series:\\n    \\\"\\\"\\\"\\n    Returns boolean Series: True on days where DIFF crosses above DEA (golden cross 金叉).\\n    Golden cross: previous diff <= dea AND current diff > dea\\n    \\\"\\\"\\\"\\n    diff = macd_df['diff']\\n    dea = macd_df['dea']\\n    cross = (diff > dea) & (diff.shift(1) <= dea.shift(1))\\n    return cross\\n\\ndef had_golden_cross_in_window(close: pd.Series, window: int = 20) -> bool:\\n    \\\"\\\"\\\"\\n    Returns True if a MACD golden cross occurred in the last `window` bars.\\n    close should have at least window + 60 bars for warm-up.\\n    \\\"\\\"\\\"\\n    macd = compute_macd(close)\\n    cross = detect_golden_cross(macd)\\n    return bool(cross.iloc[-window:].any())\\n```\\n\\n# Usage example\\n\\n```python\\n# Check if stock had MACD golden cross in last 20 trading days\\ndf = get_kline('300001', period=100)\\nclose = df['close']\\nhas_cross = had_golden_cross_in_window(close, window=20)\\n```\\n\\n# Weekly MACD from daily data\\n\\n```python\\ndef resample_to_weekly(df: pd.DataFrame) -> pd.DataFrame:\\n    \\\"\\\"\\\"Resample daily OHLCV to weekly (Friday close).\\\"\\\"\\\"\\n    df['date'] = pd.to_datetime(df['date'])\\n    df = df.set_index('date')\\n    weekly = df['close'].resample('W').last().dropna()\\n    return weekly.reset_index()\\n```\\n\\n# Histogram trend (positive and growing)\\n\\n```python\\ndef histogram_growing(macd_df: pd.DataFrame, n: int = 5) -> bool:\\n    \\\"\\\"\\\"True if histogram has been consistently increasing for last n bars.\\\"\\\"\\\"\\n    hist = macd_df['histogram'].iloc[-n:]\\n    return bool((hist.diff().iloc[1:] > 0).all())\\n```\\n\\n# Self-check\\n- [ ] Warm-up: use at least 60 bars of data before relying on MACD values\\n- [ ] Verify golden cross uses BOTH previous and current day comparison\\n- [ ] Histogram = DIFF - DEA (not DIFF - close)\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_15\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"rg -n \\\\\\\"399006|创业板|半导体|芯片|集成电路|macd\\\\\\\" /Users/tomato/Documents/potato/project/YFD -g '\\\"'!**/__pycache__/**'\\\"' | sed -n '1,260p'\\\"\",\"aggregated_output\":\"\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\", \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\